const Web3 = require('web3');
const { ethers } = require('ethers');

// Private keys for signing transactions
const privateKey1 = 'your_private_key_1';
const privateKey2 = 'your_private_key_2';

// Ethereum node provider
const provider = new Web3.providers.HttpProvider('your_ethereum_node_url');

// Wallet configuration
const wallet1 = new Web3.eth.accounts.privateKeyToAccount(privateKey1);
const wallet2 = new Web3.eth.accounts.privateKeyToAccount(privateKey2);

// Contract address and ABI
const contractAddress = 'your_contract_address';
const contractABI = JSON.parse('your_contract_abi');

// Create a contract instance
const contract = new ethers.Contract(contractAddress, contractABI, provider);

// Function to send ETH
async function sendETH(toAddress, amount) {
  const transaction = {
    from: wallet1.address,
    to: toAddress,
    value: Web3.utils.toWei(amount, 'ether'),
    gas: 21000,
    gasPrice: Web3.utils.toWei('50', 'gwei'),
  };

  const signedTransaction = await wallet1.signTransaction(transaction);
  await provider.sendTransaction(signedTransaction);
}

// Function to interact with smart contract
async function interactWithContract(functionName, ...args) {
  const transaction = {
    from: wallet2.address,
    to: contractAddress,
    data: contract.interface.encodeFunctionData(functionName, args),
    gas: 21000,
    gasPrice: Web3.utils.toWei('50', 'gwei'),
  };

  const signedTransaction = await wallet2.signTransaction(transaction);
  await provider.sendTransaction(signedTransaction);
}

// Example usage
sendETH('recipient_address', '0.1');
interactWithContract('myFunction', 'arg1', 'arg2');